## Code Example

```javascript
// Platform-specific implementation for on-device inference
class VideoAnomalyDetector {
  constructor(modelPath) {
    this.model = this.loadQuantizedModel(modelPath);
    this.frameBuffer = new CircularBuffer(30); // 1 second at 30fps
    this.driftDetector = new StatisticalDriftDetector();
  }

  async processFrame(rgbFrame, opticalFlow) {
    const rgbFeatures = await this.model.rgbBranch(rgbFrame);
    const motionFeatures = await this.model.motionBranch(opticalFlow);

    // Early exit after block 2 for latency guarantee
    if (this.confidenceAboveThreshold(rgbFeatures, motionFeatures)) {
      return this.classifier.fusedInference(rgbFeatures, motionFeatures);
    }

    // Full inference for uncertain cases
    return this.model.fullInference(rgbFrame, opticalFlow);
  }

  // Federated learning with differential privacy
  async federatedUpdate(localGradients, dpParams) {
    const noisyGradients = this.addDPNoise(localGradients, dpParams);
    return this.secureAggregation(noisyGradients);
  }
}

## Why This Is Asked

