## Code Example

```javascript
// Minimal calibration sketch (pseudo-code)
function calibrate(logits, labels, method="isotonic") {
  if (method === "platt") {
    const platt = new PlattScaler();
    platt.fit(logits, labels);
    return (l) => platt.predictProba(l);
  } else {
    const iso = new IsotonicCalibrator();
    iso.fit(logits, labels);
    return (l) => iso.predictProba(l);
  }
}
```

