// Simple logistic regression gradient step (conceptual)
function step(w, b, x, y, lr) {
  const z = 1 / (1 + Math.exp(-(dot(w, x) + b)));
  const error = y - z;
  // Update weights and bias
  for (let i = 0; i < w.length; i++) {
    w[i] += lr * error * x[i];
  }
  b += lr * error;
  return { w, b };
}
```

